        return -1;
    }

    // Initialize the structure to zero to ensure empty fields are null-terminated
    memset(hw_config, 0, sizeof(struct vm_hardware_config));

    // Format string with maximum width specifiers (one less than buffer size to reserve space for null terminator)
    // %n captures the number of characters processed to validate remaining input
    const char* format = "cpu_model=%127[^,],memory_mb=%d,disk_path=%255[^,],network_adapter=%63s%n";
    int chars_processed = 0;

    int parsed_items = sscanf(config_line,
                              format,
                              hw_config->cpu_model,
                              &hw_config->memory_mb,
                              hw_config->disk_path,
                              hw_config->network_adapter,
                              &chars_processed);

    // Verify all 4 required parameters were successfully parsed
    if (parsed_items!= 4) {
        return -1;
    }

    // Check that remaining characters are only whitespace (prevents truncated network adapter and extra garbage data)
    for (int i = chars_processed; config_line[i]!= '\0'; ++i) {
        if (!isspace((unsigned char)config_line[i])) {
            return -1;
        }
    }

    // Validate memory size is positive (invalid for VM memory to be <= 0)
    if (hw_config->memory_mb <= 0) {
        return -1;
    }

    return 0;
}

